import{_ as a,o as n,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Manage Nickname History","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/nicknames.md","filePath":"how-to/nicknames.md"}'),i={name:"how-to/nicknames.md"};function o(l,e,h,s,c,m){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="manage-nickname-history" tabindex="-1">Manage Nickname History <a class="header-anchor" href="#manage-nickname-history" aria-label="Permalink to &quot;Manage Nickname History&quot;">​</a></h1><p>Nickname history helps the tracker understand that old imports and old event records may refer to the same person under different names.</p><blockquote><p>Screenshot placeholder: player-nicknames.png</p></blockquote><h2 id="why-this-matters" tabindex="-1">Why this matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why this matters&quot;">​</a></h2><p>Without nickname history, you can end up wondering why:</p><ul><li>an older import used a different name</li><li>a player seems to disappear between events</li><li>a manual review row did not match the current visible name</li></ul><p>Nickname history keeps that story together.</p><h2 id="open-the-nickname-area" tabindex="-1">Open the nickname area <a class="header-anchor" href="#open-the-nickname-area" aria-label="Permalink to &quot;Open the nickname area&quot;">​</a></h2><ol><li>Open the player&#39;s profile.</li><li>Go to <strong>Nickname History</strong>.</li></ol><h2 id="add-a-nickname" tabindex="-1">Add a nickname <a class="header-anchor" href="#add-a-nickname" aria-label="Permalink to &quot;Add a nickname&quot;">​</a></h2><ol><li>Enter the former or alternate nickname.</li><li>Select <strong>Add nickname</strong>.</li></ol><p>Use this for old in-game names, common shorthand, or spelling changes that matter for matching.</p><h2 id="make-a-nickname-current" tabindex="-1">Make a nickname current <a class="header-anchor" href="#make-a-nickname-current" aria-label="Permalink to &quot;Make a nickname current&quot;">​</a></h2><p>Use <strong>Set current</strong> when the old nickname has become the real current player name again.</p><p>When you do that:</p><ul><li>the player&#39;s current visible name changes</li><li>the history stays intact</li></ul><h2 id="remove-a-nickname" tabindex="-1">Remove a nickname <a class="header-anchor" href="#remove-a-nickname" aria-label="Permalink to &quot;Remove a nickname&quot;">​</a></h2><p>Use <strong>Remove</strong> only for a nickname that should not stay in history.</p><p>The current nickname cannot be removed until another nickname is made current first.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Keep meaningful past names instead of cleaning them away too aggressively.</li><li>Update nickname history before rechecking messy imports.</li><li>If the person&#39;s identity changed along with alliance membership, review both the nickname and the alliance history together.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./player-profile.html">Read a Player Profile</a></li><li><a href="./../reference/alliance-membership.html">How Alliance Membership Works</a></li><li><a href="./player-sync.html">Sync Players from the Game API</a></li></ul>',23)])])}const k=a(i,[["render",o]]);export{p as __pageData,k as default};
